export function getSkillTranslation(key: string, lang: string): SkillDetail {
  const translations = skillsTranslations[key];
  if (!translations) return { name: "", levelText: "", desc: "" };
  return translations[lang] || translations["en"] || { name: "", levelText: "", desc: "" };
}
